def _universes_present(graph: nx.DiGraph) -> list[Universe]:
    seen = {Universe.code}
    for _, attrs in graph.nodes(data=True):
        raw = attrs.get("universe")
        if not raw:
            continue
        try:
            seen.add(Universe(str(raw)))
        except ValueError:
            continue
    return sorted(seen, key=lambda value: value.value)

